public class EscapeAnalysis {
    static Object leak;
    static void noLeak() {
        Object local = new Object();
        System.out.println(local != null);
    }
    static void doesLeak() {
        Object local = new Object();
        leak = local;              // escapes: stored in static field
        System.out.println(local == leak);
    }
    public static void main(String[] args) {
        noLeak();
        doesLeak();
        System.out.println(leak != null);
    }
}
